+    #[test]
+    fn pie_parser_extracts_slice_values() {
+        let parsed = parse_mermaid("pie\n  \"Dogs\" : 386\n  \"Cats\" : 85\n  \"Rats\" : 15");
+        let pie = parsed.ir.pie_meta.expect("pie_meta should be set");
+        assert_eq!(pie.slices.len(), 3);
